@each $direction in $frow-box-model-directions
      @for $amount from 0 through 5
        $multiplier: 5

        +box-model($direction, $type, $amount, $multiplier)

      @for $amount from 3 through 10
        $multiplier: 10

        +box-model($direction, $type, $amount, $multiplier)

      @if $type == "margin"
        .#{str-slice($type, 1, 1) + $direction}-auto
          @if $direction == ""
            #{$type}: auto !important

          @if $direction == "t" or $direction == "v"
            #{$type}-top: auto !important

          @if $direction == "r" or $direction == "h"
            #{$type}-right: auto !important

          @if $direction == "b" or $direction == "v"
            #{$type}-bottom: auto !important

          @if $direction == "l" or $direction == "h"
            #{$type}-left: auto !important

@if $frow-enable-columns == true
    $all-columns: ()
    $all-columns-direct: ()

    @each $size in $sizes-names
      $all-columns: append($all-columns, "[class*=col-#{$size}]", comma)

    @each $column in $all-columns
      $all-columns-direct: append($all-columns-direct, "& > #{$column}", comma)

    &.gutters
      margin-left: -$grid-gutter-width / 2
      margin-right: -$grid-gutter-width / 2

      #{$all-columns-direct}
        padding-left: $grid-gutter-width / 2
        padding-right: $grid-gutter-width / 2

    #{$all-columns}
      width: 100%

    @each $size in $sizes-names
      @media (min-width: map-get($sizes, $size))
        @for $denominator from 1 through $grid-max-columns
          @for $numerator from 1 through $denominator
            .col-#{$size}-#{$numerator}-#{$denominator}
              width: percentage($numerator / $denominator)

